const results = [];

for (const item of $input.all()) {
  const msg = item.json;
  const binaries = item.binary || {};

  const supportedTypes = [
    'application/pdf',
    'text/csv',
    'image/jpeg',
    'image/png',
    'application/vnd.ms-excel',
    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
  ];

  let idx = 0;

  for (const key of Object.keys(binaries)) {
    const file = binaries[key];

    if (!file || !file.mimeType) continue;
    if (!supportedTypes.includes(file.mimeType)) continue;

    results.push({
      json: {
        id: `gmail_${msg.id || msg.threadId}_${idx}`,
        name: file.fileName || `attachment_${idx}`,
        mimeType: file.mimeType,
        createdTime: msg.internalDate || new Date().toISOString(),
        size: String(file.fileSize || 0),

        // Email metadata (fixed field names)
        emailId: msg.id || msg.threadId,
        emailSubject: msg.Subject || msg.subject || "",
        emailFrom: msg.From || msg.from || "",

        source: 'gmail',
        binaryPropertyName: key
      },

      // ⚠️ IMPORTANT: Only pass that specific binary
      binary: {
        [key]: file
      }
    });

    idx++;
  }
}

return results.length > 0
  ? results
  : [{ json: { _empty: true } }];

const results = [];

for (const item of items) {
  if (!item.binary) continue;

  const binaryKey = Object.keys(item.binary)[0];
  const binaryData = item.binary[binaryKey];

  // Convert base64 → buffer
  const buffer = Buffer.from(binaryData.data, 'base64');

  const fileName = binaryData.fileName || "unknown";
  const mimeType = binaryData.mimeType || "";

  let extractedText = "";

  try {
    // ---- CSV FILE ----
    if (mimeType.includes('csv') || fileName.endsWith('.csv')) {
      extractedText = buffer.toString('utf-8');

      // Convert CSV → JSON
      const rows = extractedText.split('\n').map(r => r.split(','));
      const headers = rows[0];

      const jsonData = rows.slice(1).map(row => {
        const obj = {};
        headers.forEach((h, i) => obj[h.trim()] = row[i]?.trim());
        return obj;
      });

      results.push({
        json: {
          fileName,
          type: "csv",
          data: jsonData
        }
      });
    }

    // ---- TEXT FILE ----
    else if (mimeType.includes('text') || fileName.endsWith('.txt')) {
      extractedText = buffer.toString('utf-8');

      results.push({
        json: {
          fileName,
          type: "text",
          content: extractedText
        }
      });
    }

    // ---- PDF (basic extraction placeholder) ----
    else if (mimeType.includes('pdf') || fileName.endsWith('.pdf')) {
      // NOTE: n8n Code node cannot fully parse PDF text natively
      extractedText = buffer.toString('utf-8').slice(0, 2000);

      results.push({
        json: {
          fileName,
          type: "pdf",
          note: "Basic extraction only (use external service for real parsing)",
          raw_preview: extractedText
        }
      });
    }

    // ---- UNKNOWN FILE ----
    else {
      results.push({
        json: {
          fileName,
          type: "unknown",
          message: "Unsupported file type"
        }
      });
    }

  } catch (error) {
    results.push({
      json: {
        fileName,
        error: error.message
      }
    });
  }
}

return results;

