const results = [];

for (const item of $input.all()) {
  const originalData = item.json;

  const fallback = {
    category: 'unknown',
    sub_category: 'parse_error',
    confidence: 0,
    extracted_amount: null,
    currency: null,
    vendor: null,
    doc_period: null,
    notes: 'AI response could not be parsed'
  };

  let parsed = fallback;

  try {
    // ✅ NEW SOURCE (your input)
    const rawContent = originalData.output;

    if (!rawContent || rawContent.trim() === '') {
      parsed = { ...fallback, notes: 'AI returned empty response' };
    } else {
      const cleaned = rawContent
        .replace(/```json\s*/gi, '')
        .replace(/```\s*/g, '')
        .trim();

      const jsonParsed = JSON.parse(cleaned);

      parsed = {
        category: jsonParsed.category || 'unknown',
        confidence: typeof jsonParsed.confidence === 'number' ? jsonParsed.confidence : 0,

        // Map extracted_data safely
        extracted_amount: jsonParsed?.extracted_data?.amount ?? null,
        total_amount: jsonParsed?.extracted_data?.total_amount ?? null,
        vendor: jsonParsed?.extracted_data?.vendor ?? '',
        doc_period: jsonParsed?.extracted_data?.date ?? null,

        // Optional fields
        sub_category: '',
        currency: 'USD',

        notes: jsonParsed.document_type_reason || ''
      };
    }
  } catch (err) {
    parsed = {
      ...fallback,
      notes: `Parse error: ${err.message.substring(0, 80)}`
    };
  }

  // ✅ Push result per item
  results.push({
    json: {
      // ORIGINAL METADATA (safe fallback if missing)
      doc_id:            originalData.doc_id || null,
      file_name:         originalData.file_name || null,
      file_extension:    originalData.file_extension || null,
      mime_type:         originalData.mime_type || null,
      upload_date:       originalData.upload_date || null,
      source:            originalData.source || null,
      size_kb:           originalData.size_kb || null,
      drive_link:        originalData.drive_link || null,
      email_subject:     originalData.email_subject || null,

      // ✅ AI RESULTS
      category:          parsed.category,
      sub_category:      parsed.sub_category,
      confidence:        parsed.confidence,
      extracted_amount:  parsed.extracted_amount,
      total_amount:      parsed.total_amount || null,
      currency:          parsed.currency,
      vendor:            parsed.vendor,
      doc_period:        parsed.doc_period,
      notes:             parsed.notes,

      // FLAGS (very useful)
      is_incomplete:     JSON.parse(originalData.output || '{}')?.flags?.is_incomplete ?? false,
      multiple_txn:      JSON.parse(originalData.output || '{}')?.flags?.multiple_transactions ?? false,

      // STATUS
      status:            'categorized',
      missing_flag:      false,
      processed_at:      new Date().toISOString()
    }
  });
}

return results;

const docs = $input.first().json.all_documents || [];

const REQUIRED = [
  { key: 'bank_statement', label: 'Bank Statements (12 months)', min: 12 },
  { key: 'payroll',        label: 'Payroll / Salary Reports',    min: 4  },
  { key: 'invoice',        label: 'Vendor Invoices',             min: 1  },
  { key: 'receipt',        label: 'Expense Receipts',            min: 1  },
  { key: 'tax_document',   label: 'Tax Forms (W-2, 1099, GST)',  min: 1  }
];

// Count by category
const counts = {};
docs.forEach(d => {
  const c = d.category || 'unknown';
  counts[c] = (counts[c] || 0) + 1;
});

// Build checklist
const checklist = REQUIRED.map(r => {
  const found = counts[r.key] || 0;
  return {
    key:           r.key,
    label:         r.label,
    required:      r.min,
    found:         found,
    complete:      found >= r.min,
    missing_count: Math.max(0, r.min - found)
  };
});

const missing  = checklist.filter(c => !c.complete);
const complete = checklist.filter(c =>  c.complete);

// Financial totals (only docs with amounts)
const totalExpenses = docs
  .filter(d => ['receipt','invoice'].includes(d.category) && d.extracted_amount > 0)
  .reduce((sum, d) => sum + Number(d.extracted_amount), 0);

const totalIncome = docs
  .filter(d => d.category === 'payroll' && d.extracted_amount > 0)
  .reduce((sum, d) => sum + Number(d.extracted_amount), 0);

// Build vendor summary  
const vendors = {};
docs.forEach(d => {
  if (d.vendor) vendors[d.vendor] = (vendors[d.vendor] || 0) + Number(d.extracted_amount || 0);
});

// Flag anomalies
const anomalies = docs.filter(d => Number(d.extracted_amount) > 10000).map(d => 
  `${d.vendor || d.file_name}: $${d.extracted_amount} (${d.category})`
);

return [{
  json: {
    all_documents:    docs,
    checklist:        checklist,
    missing_items:    missing,
    complete_items:   complete,
    has_missing:      missing.length > 0,
    total_docs:       docs.length,
    total_expenses:   totalExpenses.toFixed(2),
    total_income:     totalIncome.toFixed(2),
    net_position:     (totalIncome - totalExpenses).toFixed(2),
    category_counts:  counts,
    vendor_summary:   vendors,
    anomalies:        anomalies,
    run_date:         new Date().toISOString().split('T')[0]
  }
}];

const data = $input.first().json;
const runDate = data.run_date;

return data.checklist.map(row => ({
  json: {
    run_date:      runDate,
    key:           row.key,
    label:         row.label,
    required:      row.required,
    found:         row.found,
    complete:      row.complete ? 'YES' : 'NO',
    missing_count: row.missing_count
  }
}));

