=={{
`Generate a tax briefing document based on the following processed financial data.

DATA:
${JSON.stringify($json, null, 2)}

INSTRUCTIONS:
- Aggregate totals where possible
- Identify missing categories (bank statements, payroll, invoices, etc.)
- Highlight low confidence or incomplete data
- Provide actionable recommendations

Generate the final accountant-ready briefing.`
}}

parameters.jsCode:
const results = [];

for (const item of $input.all()) {
  const text = item.json.briefing_text || '';

  // Skip empty safely
  if (!text || text.trim() === '') {
    results.push({
      json: {
        ...item.json,
        error: 'Empty briefing text'
      }
    });
    continue;
  }

  // Encode text → base64
  const encoded = Buffer.from(text, 'utf8').toString('base64');

  results.push({
    json: item.json,

    binary: {
      briefing_binary: {
        data: encoded,
        mimeType: 'text/plain',
        fileName: `${item.json.doc_title || 'briefing'}.txt`,
        fileExtension: 'txt'
      }
    }
  });
}

return results;

const results = [];

for (const item of $input.all()) {
  const data = item.json;

  // ✅ FIXED: use output instead of OpenAI format
  const content = data.output || '';

  const title = `Tax Briefing – ${new Date().toLocaleDateString('en-US', {
    month: 'long',
    year: 'numeric'
  })}`;

  // ---- HANDLE EMPTY ----
  if (!content || content.trim() === '') {
    results.push({
      json: {
        briefing_text: 'ERROR: AI briefing generation failed. Please review manually.',
        doc_title: title,
        generation_error: true
      }
    });
    continue;
  }

  // ---- SUCCESS CASE ----
  results.push({
    json: {
      briefing_text: content.trim(),
      doc_title: title,
      generation_error: false,
      char_count: content.length,
      generated_at: new Date().toISOString()
    }
  });
}

return results;

const results = [];

for (const item of $input.all()) {
  const d = item.json;

  // ✅ SAFE DEFAULTS
  const documents = d.all_documents || [];
  const missingItems = d.missing_items || [];
  const vendorSummary = d.vendor_summary || {};
  const anomalies = d.anomalies || [];
  const completeItems = d.complete_items || [];

  // ---- DOCUMENT LIST ----
  const docList = documents.slice(0, 25).map(doc => 
    `- ${doc.file_name} | ${doc.category} | vendor: ${doc.vendor || 'N/A'} | amount: ${doc.extracted_amount ? '$'+doc.extracted_amount : 'unknown'} | period: ${doc.doc_period || 'N/A'}`
  ).join('\n');

  // ---- MISSING LIST ----
  const missingList = missingItems.length > 0
    ? missingItems.map(i => `- ${i.label}: need ${i.missing_count} more (found ${i.found}/${i.required})`).join('\n')
    : '- None. All required documents received.';

  // ---- VENDOR LIST ----
  const vendorList = Object.entries(vendorSummary)
    .sort((a,b) => (b[1] || 0) - (a[1] || 0))
    .slice(0, 10)
    .map(([v, amt]) => `- ${v}: $${Number(amt || 0).toFixed(2)}`)
    .join('\n');

  // ---- ANOMALIES ----
  const anomalyList = anomalies.length > 0
    ? anomalies.join('\n')
    : 'None detected.';

  // ---- PROMPT ----
  const prompt = `Generate a formal accountant briefing document for tax preparation.

=== COLLECTION SUMMARY ===
Run Date: ${d.run_date || 'N/A'}
Total Documents Collected: ${d.total_docs || 0}
Documents by Category: ${JSON.stringify(d.category_counts || {})}

=== FINANCIAL OVERVIEW ===
Estimated Total Income (payroll): $${d.total_income || 0}
Estimated Total Expenses (receipts + invoices): $${d.total_expenses || 0}
Net Position: $${d.net_position || 0}

=== TOP VENDORS BY SPEND ===
${vendorList || 'No vendor data available.'}

=== DOCUMENT CHECKLIST ===
Complete items: ${completeItems.map(i => i.label).join(', ') || 'None'}
Missing items:
${missingList}

=== ANOMALIES (amounts over $10,000) ===
${anomalyList}

=== DOCUMENT LIST ===
${docList || 'No documents found.'}

=== INSTRUCTIONS ===
Write a professional accountant briefing with EXACTLY these sections:

1. EXECUTIVE SUMMARY
2. INCOME ANALYSIS
3. EXPENSE ANALYSIS
4. DOCUMENT STATUS
5. FLAGS AND ANOMALIES
6. RECOMMENDED NEXT STEPS

Use formal language. Include specific dollar figures. Be concise but thorough.`;

  // ✅ Push per item
  results.push({
    json: {
      ...d,
      briefing_prompt: prompt
    }
  });
}

return results;
